UIFriendItem = class("UIFriendItem", IGUIWindow)

function UIFriendItem:onLoad()
    print("UIFriendItem:onLoad()")
    self.icon = self:getChildWindow(0 , GUIType.UrlImage)
    self.icon:setDefaultImage("set:userItem.json image:icon")
    self.name = self:getChildWindow(1)
    self.status = self:getChildWindow(2)
    self.sex = self:getChildWindow(3, GUIType.StaticImage)
    self.deleteBtn = self:getChildWindow(4):GetChildByIndex(1)
    self.deleteBtn:registerEvent(GUIEvent.ButtonClick, function()
        self:onDeleteButtonEvent()
    end)
    self.visitBtn = self:getChildWindow(4):GetChildByIndex(0)
    self.visitBtn:registerEvent(GUIEvent.ButtonClick, function()
        self:onVisitButtonEvent()
    end)
    self.visitBtn:SetVisible(false)
    self.ban = self:getChildWindow(4):GetChildByIndex(2)
    self.ban:SetVisible(true)

    self.data = {}
end

function UIFriendItem:onDeleteButtonEvent()
    local master = 0
    local member = 0
    local tips = "gui_delete_common_friend"
    local smallTips = ""
    local deleteType = -1

    if MultiBuildData:checkIsBuildMaster(GameData.userId) then
        if MultiBuildData:checkIsBuildMember(self.data.userId) then
            master = GameData.userId
            member = self.data.userId
            smallTips = "this_will_expel_build_group"
            deleteType = SkyBlockWeb.KickOutType.MASTER_KICK_OUT
        end

    elseif MultiBuildData:checkIsBuildMaster(self.data.userId) then
        if MultiBuildData:checkIsBuildMember(GameData.userId) then
            master = self.data.userId
            member = GameData.userId
            smallTips = "you_will_lost_a_build"
            deleteType = SkyBlockWeb.KickOutType.SELF_LEAVE
        end
    end

    local content = string.format(Lang:getString(tips), tostring(self.data.nickName))
    GUITipDialog:onShowTipDialog(content, GUITipDialog.TipType.COMMON, Lang:getString(smallTips), function(isSure)
                if isSure then
                    if deleteType ~= -1 then
                        MultiBuildData:postKickOut(master, member, deleteType, true)
                    end
                    MultiBuildData:postDeleteFriend(self.data.userId)
                end
            end)
end

function UIFriendItem:onVisitButtonEvent()
    PacketSender:sendCallOnManor(self.data.userId, 3, true, 0)
end

function UIFriendItem:setItemData(data)


    self.data = data
    self:setDataUpdate()
end

function UIFriendItem:getStatusText()
    if self.data.status == 20 then
        if self.data.gameId == BaseMain:getGameType() then
            return Lang:getString("online")
        end
    end
    return Lang:getString("offline")
end

function UIFriendItem:getSexIcon()
    if self.data.sex == 2 then
        return "set:skyblock_friend.json image:sex_girl"
    end
    return "set:skyblock_friend.json image:sex_boy"
end

function UIFriendItem:setDataUpdate()
    self.icon:setUrl(self.data.picUrl)
    self.name:SetText(self.data.nickName)
    self.status:SetText(self:getStatusText())
    self.sex:SetImage(self:getSexIcon())

    if self.data.isPlayCurGame == 1 then
        self.visitBtn:SetVisible(true)
        self.ban:SetVisible(false)
    end
end

function UIFriendItem:sureDeleteFriend()
    
end

